import React from 'react'
import { WeatherProvider, useWeatherContext } from './context/WeatherContext'
import { ThemeProvider } from './context/ThemeContext'
import AppShell from './components/layout/AppShell'

// A small inner component so we can consume the contexts before rendering the shell
function AppInner() {
  const { location, currentWeather, isLoading, isSuccess, error } = useWeatherContext();

  if (isLoading && !currentWeather) {
    return (
      <div className="startup-loading">
        <h1>Atmosphere Loading...</h1>
        {/* We will replace this with a proper Glass Loading spinner later */}
      </div>
    );
  }

  // Debug snippet just to verify API response on load
  if (isSuccess && currentWeather) {
    console.log('Weather Loaded for:', location.name, currentWeather);
  }

  return <AppShell />
}

function App() {
  return (
    <WeatherProvider>
      <ThemeProvider>
        <AppInner />
      </ThemeProvider>
    </WeatherProvider>
  )
}

export default App

import React from 'react';
import { motion } from 'framer-motion';
import GlassCard from '../ui/GlassCard';

export default function DailyForecast({ forecastData }) {
    if (!forecastData || !forecastData.list) return null;

    // The OWM /forecast endpoint returns 3-hour chunks (40 items = 5 days)
    // We need to group them by day and find daily high/low
    const dailyData = {};

    forecastData.list.forEach(item => {
        const date = new Date(item.dt * 1000);
        const dayStr = date.toLocaleDateString('en-US', { weekday: 'short' });

        if (!dailyData[dayStr]) {
            dailyData[dayStr] = {
                dt: item.dt,
                day: dayStr,
                temp_min: item.main.temp_min,
                temp_max: item.main.temp_max,
                condition: item.weather[0]
            };
        } else {
            // update min/max
            if (item.main.temp_min < dailyData[dayStr].temp_min) {
                dailyData[dayStr].temp_min = item.main.temp_min;
            }
            if (item.main.temp_max > dailyData[dayStr].temp_max) {
                dailyData[dayStr].temp_max = item.main.temp_max;
            }
        }
    });

    const uniqueDays = Object.values(dailyData).slice(0, 5); // ensure only 5

    return (
        <GlassCard className="daily-forecast">
            <h3>5.Day Forecast</h3>
            <div className="daily-list">
                {uniqueDays.map((day, index) => (
                    <motion.div
                        key={day.day}
                        className="daily-item"
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        transition={{ delay: index * 0.1 }}
                    >
                        <span className="day-name">{index === 0 ? 'Today' : day.day}</span>
                        <div className="daily-icon-wrapper">
                            {/* Fallback to condition text */}
                            <span className="daily-cond">{day.condition.main}</span>
                        </div>
                        <div className="daily-temps">
                            <span className="low">{Math.round(day.temp_min)}&deg;</span>
                            <div className="temp-bar">
                                <div className="temp-bar-fill" style={{
                                    // Mock gradient width calculation based on temp bounds
                                    width: '60%',
                                    marginLeft: '20%'
                                }}></div>
                            </div>
                            <span className="high">{Math.round(day.temp_max)}&deg;</span>
                        </div>
                    </motion.div>
                ))}
            </div>
        </GlassCard>
    );
}

import React, { useRef, useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import GlassCard from '../ui/GlassCard';

export default function HourlyForecast({ forecastData }) {
    const scrollRef = useRef(null);
    const [pathData, setPathData] = useState('');
    const [points, setPoints] = useState([]);

    if (!forecastData || !forecastData.list) return null;

    // Grab the next 12 items (36 hours) for a good scroll deck
    const nextHours = forecastData.list.slice(0, 12);

    const formatHour = (dt) => {
        const date = new Date(dt * 1000);
        return date.toLocaleTimeString([], { hour: 'numeric', hour12: true });
    };

    // Card width + gap = 80px + 16px (1rem gap)
    const cardStep = 96;

    useEffect(() => {
        // Calculate the bezier curve for the temperature trend
        const temps = nextHours.map(item => item.main.temp);
        const minTemp = Math.min(...temps);
        const maxTemp = Math.max(...temps);
        const range = maxTemp - minTemp || 1; // avoid / 0

        // SVG drawing area is roughly 120px tall, positioned behind cards
        const height = 120;

        // Map temperatures to SVG Y coordinates (inverted so higher temp = lower Y)
        const newPoints = temps.map((temp, i) => {
            const x = (i * cardStep) + (80 / 2); // Center of each 80px card
            // Add padding so curve doesn't hit absolute top/bottom
            const normalizedY = ((temp - minTemp) / range);
            const y = height - (normalizedY * (height - 40)) - 20;
            return { x, y, temp: Math.round(temp) };
        });

        // Generate smooth Bezier curve string
        if (newPoints.length > 0) {
            let d = `M ${newPoints[0].x} ${newPoints[0].y}`;

            for (let i = 0; i < newPoints.length - 1; i++) {
                const current = newPoints[i];
                const next = newPoints[i + 1];

                // Control points for smooth bezier (horizontal tangents)
                const ctrl1X = current.x + (next.x - current.x) / 2;
                const ctrl1Y = current.y;
                const ctrl2X = current.x + (next.x - current.x) / 2;
                const ctrl2Y = next.y;

                d += ` C ${ctrl1X} ${ctrl1Y}, ${ctrl2X} ${ctrl2Y}, ${next.x} ${next.y}`;
            }

            setPathData(d);
            setPoints(newPoints);
        }

    }, [forecastData]);

    return (
        <GlassCard style={{ padding: '1.5rem', position: 'relative', overflow: 'hidden' }}>
            <h3 style={{ marginBottom: '1rem', alignSelf: 'flex-start' }}>Hourly Outlook</h3>

            {/* Left/Right scroll fade masks */}
            <div style={{
                position: 'absolute', left: 0, top: 0, bottom: 0, width: '40px',
                background: 'linear-gradient(to right, rgba(15,23,42,0.6), transparent)', zIndex: 5, pointerEvents: 'none'
            }} />
            <div style={{
                position: 'absolute', right: 0, top: 0, bottom: 0, width: '40px',
                background: 'linear-gradient(to left, rgba(15,23,42,0.6), transparent)', zIndex: 5, pointerEvents: 'none'
            }} />

            <div
                ref={scrollRef}
                style={{
                    display: 'flex', gap: '1rem', overflowX: 'auto', paddingBottom: '1rem',
                    scrollBehavior: 'smooth', scrollSnapType: 'x mandatory',
                    position: 'relative' // relative for absolute SVG child
                }}
                className="custom-scrollbar"
            >
                {/* Background SVG Trendline */}
                <svg
                    style={{
                        position: 'absolute', top: '10px', left: 0,
                        width: `${nextHours.length * cardStep}px`, height: '120px',
                        zIndex: 0, pointerEvents: 'none'
                    }}
                >
                    <path
                        d={pathData}
                        fill="none"
                        stroke="rgba(255,255,255,0.2)"
                        strokeWidth="4"
                        strokeLinecap="round"
                    />
                </svg>

                {/* Forecast Cards */}
                {nextHours.map((item, index) => {
                    const pop = item.pop || 0; // Probability of precipitation (0-1)
                    const isCurrent = index === 0;

                    return (
                        <motion.div
                            key={item.dt}
                            style={{
                                display: 'flex', flexDirection: 'column', alignItems: 'center',
                                minWidth: '80px', width: '80px', flexShrink: 0,
                                padding: '1rem 0.5rem',
                                background: isCurrent ? 'rgba(255,255,255,0.15)' : 'rgba(0,0,0,0.2)',
                                backdropFilter: 'blur(8px)',
                                borderRadius: '20px', border: isCurrent ? '1px solid rgba(255,255,255,0.4)' : '1px solid rgba(255,255,255,0.1)',
                                zIndex: 1, scrollSnapAlign: 'start'
                            }}
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: index * 0.05 }}
                            whileHover={{ y: -5, background: 'rgba(255,255,255,0.2)' }}
                        >
                            <span style={{ fontSize: '0.9rem', marginBottom: '0.5rem', fontWeight: isCurrent ? 'bold' : 'normal' }}>
                                {isCurrent ? 'Now' : formatHour(item.dt)}
                            </span>

                            {/* Tiny representation of weather */}
                            <img
                                src={`https://openweathermap.org/img/wn/${item.weather[0].icon}.png`}
                                alt={item.weather[0].main}
                                style={{ width: '40px', height: '40px', filter: 'drop-shadow(0 2px 4px rgba(0,0,0,0.3))' }}
                            />

                            <span style={{ fontSize: '1.2rem', fontWeight: 'bold', marginTop: '0.5rem' }}>
                                {Math.round(item.main.temp)}&deg;
                            </span>

                            {/* Precipitation Bar */}
                            {pop > 0 && (
                                <div style={{
                                    width: '30px', height: '4px', background: 'rgba(255,255,255,0.1)',
                                    borderRadius: '2px', marginTop: '0.5rem', overflow: 'hidden'
                                }}>
                                    <div style={{
                                        width: `${pop * 100}%`, height: '100%',
                                        background: '#4facfe', borderRadius: '2px'
                                    }} />
                                </div>
                            )}
                        </motion.div>
                    )
                })}
            </div>
        </GlassCard>
    );
}

import React from 'react'
import { useThemeContext } from '../../context/ThemeContext'
import { useWeatherContext } from '../../context/WeatherContext'
import BackgroundScene from './BackgroundScene'

import HeroWeather from '../weather/HeroWeather';
import FeelsLike from '../weather/FeelsLike';
import WindCompass from '../weather/WindCompass';
import AQIGauge from '../weather/AQIGauge';
import SunriseSunset from '../weather/SunriseSunset';

import HourlyForecast from '../forecast/HourlyForecast';
import DailyForecast from '../forecast/DailyForecast';
import SearchBar from '../search/SearchBar';
import RecentCities from '../search/RecentCities';

export default function AppShell() {
    const { themeClass, isDay } = useThemeContext();
    const {
        location,
        currentWeather,
        forecast,
        units,
        toggleUnits,
        isLoading
    } = useWeatherContext();

    return (
        <div className={`app-shell ${themeClass}`}>
            <BackgroundScene />

            <main className="dashboard-container">
                <header className="dashboard-header" style={{ marginBottom: '2rem' }}>
                    <h1 className="logo">SKYGLASS</h1>
                    {/* SearchBar is now fixed floating pill, RecentCities can stay in header */}
                    <div className="search-section" style={{ marginTop: '40px' }}>
                        <RecentCities />
                    </div>
                </header>

                <SearchBar /> {/* Will render as floating pill */}

                {isLoading ? (
                    <div className="loading-state">
                        <div className="spinner"></div>
                        <p>Gathering atmosphere...</p>
                    </div>
                ) : (
                    <div className="dashboard-grid">
                        {currentWeather && (
                            <div className="dashboard-left">
                                <HeroWeather
                                    weather={currentWeather}
                                    locationName={location.name}
                                    isDay={isDay}
                                    onToggleUnits={toggleUnits}
                                />

                                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
                                    <WindCompass
                                        speed={currentWeather.wind.speed}
                                        deg={currentWeather.wind.deg}
                                        unit={units === 'metric' ? 'km/h' : 'mph'}
                                    />
                                    {/* Temporary hardcoded AQI mapping based on OpenWeatherMap API tier limitations unless we fetched it */}
                                    {/* Passing a random 1-5 for visual demonstration since AQI wasn't in the base payload */}
                                    <AQIGauge aqi={Math.floor(Math.random() * 5) + 1} />
                                </div>

                                <SunriseSunset
                                    sys={currentWeather.sys}
                                    timezone={currentWeather.timezone}
                                />

                                <FeelsLike
                                    feelsLike={currentWeather.main.feels_like}
                                    humidity={currentWeather.main.humidity}
                                    uvi={8} // Placeholder UVI
                                />
                            </div>
                        )}

                        {forecast && (
                            <div className="dashboard-right">
                                <HourlyForecast forecastData={forecast} />
                                <DailyForecast forecastData={forecast} />
                            </div>
                        )}
                    </div>
                )}
            </main>
        </div>
    )
}

import React from 'react';
import { motion } from 'framer-motion';

export default function CloudDrift({ density = 'few' }) // few, scattered, broken, overcast
{
    const cloudCount = density === 'few' ? 2 : density === 'scattered' ? 4 : density === 'broken' ? 6 : 8;

    const clouds = Array.from({ length: cloudCount }).map((_, i) => ({
        id: i,
        y: Math.random() * 40, // Top 40% of screen
        duration: Math.random() * 100 + 100, // Very slow drift
        delay: Math.random() * -100, // Start half-way across screen
        scale: Math.random() * 1 + 1,
        opacity: density === 'overcast' ? 0.7 : Math.random() * 0.3 + 0.1,
        zIndex: Math.floor(Math.random() * 3)
    }));

    return (
        <div className="particle-layer cloud-layer">
            {clouds.map((cloud) => (
                <motion.div
                    key={cloud.id}
                    className="parallax-cloud"
                    style={{
                        top: `${cloud.y}vh`,
                        transform: `scale(${cloud.scale})`,
                        opacity: cloud.opacity,
                        zIndex: cloud.zIndex
                    }}
                    animate={{ x: ['-20vw', '120vw'] }}
                    transition={{
                        duration: cloud.duration,
                        repeat: Infinity,
                        delay: cloud.delay,
                        ease: "linear"
                    }}
                >
                    {/* SVG cloud shapes generally applied via CSS background-image for simplicity, or complex SVG child here */}
                    <div className="cloud-blob"></div>
                </motion.div>
            ))}

            {density === 'overcast' && <div className="overcast-overlay"></div>}
        </div>
    );
}

