import React, { useEffect, useRef } from 'react';
import { useWeatherContext } from '../../context/WeatherContext';

export default function RainParticles() {
    const canvasRef = useRef(null);
    const { currentWeather } = useWeatherContext();

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas || !currentWeather) return;

        const ctx = canvas.getContext('2d');
        let animationFrameId;

        // Resize canvas to window dimensions
        const resize = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        };
        window.addEventListener('resize', resize);
        resize();

        // Interpret Weather ID for Rain Intensity
        const conditionId = currentWeather.weather[0].id;
        let numDrops = 150; // Default light rain
        let minSpeed = 12;
        let maxSpeed = 20;
        let minLength = 15;
        let maxLength = 30;

        if (conditionId >= 300 && conditionId <= 321) {
            // Drizzle
            numDrops = 80;
            minSpeed = 8; maxSpeed = 15;
            minLength = 10; maxLength = 20;
        } else if (conditionId === 500 || conditionId === 501) {
            // Light Rain
            numDrops = 150;
        } else if (conditionId === 502 || conditionId === 503 || conditionId === 504) {
            // Moderate Rain
            numDrops = 250;
            minSpeed = 18; maxSpeed = 28;
        } else if (conditionId === 511 || (conditionId >= 521 && conditionId <= 531) || (conditionId >= 200 && conditionId < 300)) {
            // Heavy Rain or Thunderstorm
            numDrops = 400;
            minSpeed = 25; maxSpeed = 40;
            minLength = 20; maxLength = 45;
        }

        const windSpeed = currentWeather.wind ? currentWeather.wind.speed : 0;
        const windDeg = currentWeather.wind ? currentWeather.wind.deg : 0;

        // Base angle modifier derived from wind direction
        // Assume wind from left (blows right) or right (blows left)
        const windDirectionModifier = (windDeg > 180) ? -1 : 1;

        class Drop {
            constructor() {
                this.reset(true);
            }

            reset(randomizeY = false) {
                this.x = Math.random() * canvas.width;
                // If initializing, scatter droplets all over screen. If resetting after falling, put at top.
                this.y = randomizeY ? (Math.random() * canvas.height) - canvas.height : -100;

                this.length = minLength + Math.random() * (maxLength - minLength);
                this.baseSpeed = minSpeed + Math.random() * (maxSpeed - minSpeed);

                // Add wind speed boost
                this.speed = this.baseSpeed + (windSpeed * 0.3);

                this.opacity = 0.3 + Math.random() * 0.4; // 0.3 to 0.7

                // Calculate angle in radians. 15 degrees base tilt + wind-influenced tilt
                // Wait, spec: "angle: 15 + (windDeg > 180 ? -1 : 1) * random(5, 25)"
                const degAngle = 15 + (windDirectionModifier * (5 + Math.random() * 20));
                this.angle = degAngle * (Math.PI / 180);
            }

            update() {
                this.y += this.speed;
                this.x += Math.sin(this.angle) * this.speed * 0.3;

                // Reset drop if it passes bottom
                if (this.y > canvas.height + this.length) {
                    this.reset();
                }

                // Wrap horizontally if wind blows offscreen
                if (this.x > canvas.width + 100) this.x = -50;
                else if (this.x < -100) this.x = canvas.width + 50;
            }

            draw() {
                ctx.beginPath();
                ctx.moveTo(this.x, this.y);
                const endX = this.x + Math.sin(this.angle) * this.length;
                const endY = this.y + Math.cos(this.angle) * this.length;
                ctx.lineTo(endX, endY);

                ctx.strokeStyle = `rgba(174, 214, 241, ${this.opacity})`;
                ctx.lineWidth = 1;
                ctx.stroke();
            }
        }

        const drops = Array.from({ length: numDrops }).map(() => new Drop());

        const render = () => {
            // Clear entire canvas frame
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            drops.forEach(drop => {
                drop.update();
                drop.draw();
            });

            animationFrameId = requestAnimationFrame(render);
        };

        render();

        return () => {
            window.removeEventListener('resize', resize);
            cancelAnimationFrame(animationFrameId);
        };
    }, [currentWeather]);

    return (
        <canvas
            ref={canvasRef}
            className="particle-layer rain-layer"
            style={{ position: 'fixed', inset: 0, pointerEvents: 'none', zIndex: 1 }}
        />
    );
}

