import React from 'react';

export default function SnowParticles() {
    // Generate exactly 60 depth-layered flakes
    const flakes = Array.from({ length: 60 }).map((_, i) => {
        const size = Math.random() * 8 + 4; // 4px to 12px
        const isSmall = size < 6;

        return {
            id: i,
            size,
            opacity: Math.random() * 0.4 + 0.5, // 0.5 to 0.9
            left: Math.random() * 100, // 0 to 100 vw
            duration: Math.random() * 6 + 4, // 4s to 10s
            delay: Math.random() * -10, // Negative delay to start mid-animation
            blur: isSmall ? 'blur(1px)' : 'none',
            translateX: Math.random() * 200 - 100 // -100px to 100px drift
        };
    });

    return (
        <div className="particle-layer snow-layer" style={{ pointerEvents: 'none', zIndex: 1 }}>
            {flakes.map((flake) => (
                <div
                    key={flake.id}
                    className="snowflake"
                    style={{
                        position: 'fixed',
                        top: '-20px',
                        left: `${flake.left}vw`,
                        width: `${flake.size}px`,
                        height: `${flake.size}px`,
                        borderRadius: '50%',
                        background: `rgba(255, 255, 255, ${flake.opacity})`,
                        filter: flake.blur,
                        // Custom CSS property used by the @keyframes to drift dynamically
                        '--snow-drift': `${flake.translateX}px`,
                        animation: `snowfall ${flake.duration}s linear ${flake.delay}s infinite`
                    }}
                />
            ))}
        </div>
    );
}

import React from 'react';
import { motion } from 'framer-motion';

export default function Starfield() {
    const stars = Array.from({ length: 150 }).map((_, i) => ({
        id: i,
        x: Math.random() * 100, // vw
        y: Math.random() * 100, // vh
        size: Math.random() * 2 + 1, // 1px to 3px
        duration: Math.random() * 3 + 2, // twinkle speed
        delay: Math.random() * 5,
        opacity: Math.random() * 0.5 + 0.3
    }));

    return (
        <div className="particle-layer starfield">
            {/* Milky way diagonal gradient overlay */}
            <div className="milky-way" style={{
                position: 'absolute',
                top: '-50%', left: '-50%', width: '200%', height: '200%',
                background: 'radial-gradient(ellipse at center, rgba(255,255,255,0.05) 0%, transparent 50%)',
                transform: 'rotate(25deg)'
            }}></div>

            {/* Moon glow */}
            <div className="moon-glow" style={{
                position: 'absolute', top: '15%', right: '15%',
                width: '100px', height: '100px', borderRadius: '50%',
                boxShadow: '0 0 60px 20px rgba(255,255,255,0.2), inset -10px -10px 20px rgba(0,0,0,0.5)',
                background: '#fcfccc'
            }}></div>

            {stars.map((star) => (
                <motion.div
                    key={star.id}
                    className="star"
                    style={{
                        position: 'absolute',
                        left: `${star.x}vw`,
                        top: `${star.y}vh`,
                        width: `${star.size}px`,
                        height: `${star.size}px`,
                        backgroundColor: 'white',
                        borderRadius: '50%',
                        boxShadow: '0 0 4px rgba(255,255,255,0.8)'
                    }}
                    initial={{ opacity: star.opacity }}
                    animate={{
                        opacity: [star.opacity, star.opacity * 0.2, star.opacity]
                    }}
                    transition={{
                        duration: star.duration,
                        repeat: Infinity,
                        delay: star.delay,
                        ease: "easeInOut"
                    }}
                />
            ))}
        </div>
    );
}

import React from 'react';
import { motion } from 'framer-motion';

export default function SunRays() {
    const rays = Array.from({ length: 8 }).map((_, i) => ({
        id: i,
        rotate: (360 / 8) * i,
        duration: Math.random() * 10 + 20, // Slow rotation
        opacity: Math.random() * 0.15 + 0.05
    }));

    return (
        <div className="particle-layer sun-rays-layer" style={{
            display: 'flex', justifyContent: 'center', alignItems: 'center', overflow: 'hidden'
        }}>
            {/* Central Sun Corona Effect */}
            <motion.div
                className="sun-corona"
                style={{
                    position: 'absolute',
                    width: '30vh', height: '30vh',
                    background: 'radial-gradient(circle, rgba(255,255,255,0.8) 0%, rgba(255,200,100,0.2) 40%, transparent 70%)',
                    borderRadius: '50%'
                }}
                animate={{ scale: [1, 1.1, 1], opacity: [0.8, 1, 0.8] }}
                transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
            />

            {/* Rotating Crepuscular Rays */}
            <motion.div
                className="rays-container"
                style={{ position: 'absolute', width: '200vw', height: '200vw', transformOrigin: 'center' }}
                animate={{ rotateZ: [0, 360] }}
                transition={{ duration: 120, repeat: Infinity, ease: "linear" }}
            >
                {rays.map((ray) => (
                    <div
                        key={ray.id}
                        className="sun-ray"
                        style={{
                            position: 'absolute',
                            top: '50%', left: '50%',
                            width: '100%', height: '5vh',
                            background: 'linear-gradient(90deg, rgba(255,255,255,0) 0%, rgba(255,255,255,0.15) 50%, rgba(255,255,255,0) 100%)',
                            transformOrigin: '0 50%',
