import React from 'react';
import { motion } from 'framer-motion';

/**
 * Reusable Glassmorphic Card Container
 * Handles the 3D perspective hover effects, blur filters, and atmospheric lighting
 */
export default function GlassCard({
    children,
    className = '',
    style = {},
    variant = 'default', // 'default', 'subtle', 'highlight'
    hover3D = false
}) {

    const baseClasses = `glass-container variant-${variant} ${className}`;

    // Standard CSS-based glass module (no complicated JS 3D to save performance unless hover3D requested)
    if (!hover3D) {
        return (
            <div className={baseClasses} style={style}>
                {children}
            </div>
        );
    }

    // Framer Motion 3D Hover Effect
    return (
        <motion.div
            className={baseClasses}
            style={{
                ...style,
                perspective: '1000px',
                transformStyle: 'preserve-3d'
            }}
            whileHover={{
                scale: 1.02,
                boxShadow: '0 20px 40px 0 rgba(0,0,0,0.3)',
            }}
            transition={{ type: 'spring', stiffness: 400, damping: 25 }}
        >
            <div className="glass-content-wrapper">
                {children}
            </div>
        </motion.div>
    );
}

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import GlassCard from '../ui/GlassCard';

export default function AQIGauge({ aqi }) {
    // OpenWeatherMap AQI values: 1=Good, 2=Fair, 3=Moderate, 4=Poor, 5=Very Poor
    // Map these to our 0-300 scale for the 270 degree gauge visual
    const aqiMapping = {
        1: { value: 25, label: "Good", color: "#22c55e" },
        2: { value: 75, label: "Fair", color: "#facc15" },
        3: { value: 125, label: "Moderate", color: "#f97316" },
        4: { value: 175, label: "Poor", color: "#ef4444" },
        5: { value: 250, label: "Hazardous", color: "#7f1d1d" },
    };

    const currentData = aqiMapping[aqi] || aqiMapping[1];

    // We want the needle to animate from 0 on mount
    const [animatedValue, setAnimatedValue] = useState(0);

    useEffect(() => {
        // Trigger spring animation after mount
        const timeout = setTimeout(() => {
            setAnimatedValue(currentData.value);
        }, 100);
        return () => clearTimeout(timeout);
    }, [currentData.value]);

    // Calculate rotation for 270 degree arc (-135 to +135 degrees)
    // Scale 0-300 maps to -135 to 135
    const rotation = -135 + (Math.min(animatedValue, 300) / 300) * 270;

    return (
        <GlassCard style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
            <h3 style={{ alignSelf: 'flex-start', margin: '0 0 1rem 0' }}>Air Quality</h3>

            <div style={{ position: 'relative', width: '160px', height: '140px', display: 'flex', justifyContent: 'center' }}>
                {/* SVG Gauge Background */}
                <svg width="160" height="160" viewBox="0 0 100 100" style={{ position: 'absolute', top: 0, left: 0 }}>
                    {/* Define gradients for the stroke */}
                    <defs>
                        <linearGradient id="aqi-grad" x1="0%" y1="100%" x2="100%" y2="0%">
                            <stop offset="0%" stopColor="#22c55e" />
                            <stop offset="25%" stopColor="#facc15" />
                            <stop offset="50%" stopColor="#f97316" />
                            <stop offset="75%" stopColor="#ef4444" />
                            <stop offset="100%" stopColor="#7f1d1d" />
                        </linearGradient>
                    </defs>

                    {/* Background track (grey) - 270 arc */}
                    <path
                        d="M 20 80 A 45 45 0 1 1 80 80"
                        fill="none"
                        stroke="rgba(255,255,255,0.1)"
                        strokeWidth="8"
                        strokeLinecap="round"
                    />

                    {/* Colored track overlay */}
                    <path
                        d="M 20 80 A 45 45 0 1 1 80 80"
                        fill="none"
                        stroke="url(#aqi-grad)"
                        strokeWidth="8"
                        strokeLinecap="round"
                        strokeOpacity="0.8"
                    />
                </svg>

                {/* Animated Needle */}
                <motion.div
                    style={{
                        position: 'absolute',
                        bottom: '20px', left: '50%',
                        width: '4px', height: '60px',
                        backgroundColor: 'white',
                        borderRadius: '2px',
                        transformOrigin: 'bottom center',
                        boxShadow: '0 0 10px rgba(0,0,0,0.5)'
                    }}
                    animate={{ rotateZ: rotation }}
                    transition={{ type: 'spring', stiffness: 60, damping: 15 }}
                />

                {/* Center Pivot Point */}
                <div style={{
                    position: 'absolute', bottom: '14px', left: '50%', transform: 'translateX(-50%)',
                    width: '16px', height: '16px',
                    backgroundColor: 'white', borderRadius: '50%',
                    boxShadow: '0 2px 5px rgba(0,0,0,0.5)'
                }} />

                {/* Text Readout */}
                <div style={{
                    position: 'absolute', bottom: '-10px', width: '100%',
                    textAlign: 'center', display: 'flex', flexDirection: 'column'
                }}>
                    <span style={{ fontSize: '1.2rem', fontWeight: 'bold' }}>{currentData.label}</span>
                    <span style={{ fontSize: '0.8rem', color: currentData.color }}>Level {aqi}</span>
                </div>
            </div>
        </GlassCard>
    );
}

import React, { useRef, useState, useEffect } from 'react';
import { motion, useMotionValue, useSpring, useTransform } from 'framer-motion';
import CountUp from 'react-countup';
import WeatherIcon3D from './WeatherIcon3D';

export default function HeroWeather({ weather, locationName, isDay, onToggleUnits }) {
    const cardRef = useRef(null);
    const [currentTime, setCurrentTime] = useState(new Date());

    // 3D Tilt Logic
    const x = useMotionValue(0);
    const y = useMotionValue(0);

    const mouseXSpring = useSpring(x, { stiffness: 300, damping: 30 });
    const mouseYSpring = useSpring(y, { stiffness: 300, damping: 30 });

    const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ['8deg', '-8deg']);
    const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ['-8deg', '8deg']);

    // Glass Reflection
    const glareX = useTransform(mouseXSpring, [-0.5, 0.5], ['0%', '100%']);
    const glareY = useTransform(mouseYSpring, [-0.5, 0.5], ['0%', '100%']);

    const handleMouseMove = (e) => {
        if (!cardRef.current) return;
        const rect = cardRef.current.getBoundingClientRect();

        // Calculate relative mouse position (-0.5 to 0.5)
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;
        x.set(mouseX / rect.width - 0.5);
        y.set(mouseY / rect.height - 0.5);
    };

    const handleMouseLeave = () => {
        x.set(0);
        y.set(0);
    };

    // Live Clock
    useEffect(() => {
        const timer = setInterval(() => setCurrentTime(new Date()), 1000);
        return () => clearInterval(timer);
    }, []);

    if (!weather) return null;

    const current = weather.main;
    const condition = weather.weather[0];

    return (
        <motion.div
            ref={cardRef}
            className="hero-weather-card glass-container"
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, ease: "easeOut" }}
            style={{
                perspective: '1000px',
                rotateX,
                rotateY,
                transformStyle: 'preserve-3d'
            }}
        >
            {/* Dynamic Glare Reflection Overlay */}
            <motion.div
                className="glare-reflection"
                style={{
                    position: 'absolute', inset: 0, zIndex: 5, pointerEvents: 'none',
                    background: 'radial-gradient(circle at center, rgba(255,255,255,0.2) 0%, transparent 40%)',
                    left: glareX, top: glareY, transform: 'translate(-50%, -50%)',
                    width: '200%', height: '200%'
                }}
            />

            <div className="hero-content" style={{ transform: 'translateZ(30px)' }}>
                <div className="hero-header">
                    <h2>{locationName}</h2>
                    <p className="local-time">
                        {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </p>
                </div>

                <div className="hero-center">
                    <motion.div
                        className="hero-icon-wrapper"
                        style={{ transform: 'translateZ(60px)' }}
                        whileHover={{ translateZ: '80px', scale: 1.05 }}
                    >
                        <WeatherIcon3D conditionId={condition.id} isDay={isDay} />
                    </motion.div>

                    <div className="temp-interactive" onClick={onToggleUnits} title="Click to toggle units">
                        <span className="temp-number">
                            <CountUp
                                end={Math.round(current.temp)}
                                duration={2}
                                preserveValue={true}
                            />
                        </span>
                        <span className="degree-symbol">&deg;</span>
                    </div>
                </div>

                <div className="hero-footer">
                    <p className="hero-condition">{condition.description}</p>
                    <div className="hero-high-low">
                        <span>H: {Math.round(current.temp_max)}&deg;</span>
                        <span>L: {Math.round(current.temp_min)}&deg;</span>
                    </div>
                </div>
            </div>
        </motion.div>
    );
}

import React from 'react';
import { motion } from 'framer-motion';
import GlassCard from '../ui/GlassCard';
import { useThemeContext } from '../../context/ThemeContext';

export default function SunriseSunset({ sys, timezone }) {
    const { isDay, dayNightRatio } = useThemeContext();

    if (!sys || !sys.sunrise || !sys.sunset) return null;

    // Convert UNIX timestamps to local timezone strings
    const formatTime = (ts) => {
        const date = new Date((ts + timezone) * 1000); // Adjust for API timezone offset
        return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', timeZone: 'UTC' });
    };

    const sunriseStr = formatTime(sys.sunrise);
    const sunsetStr = formatTime(sys.sunset);

    // dayNightRatio is 0 at sunrise, 1 at sunset. Nighttime it's > 1 or < 0.
    // Clamp between 0 and 1 for the daytime arc. Focus on day arc primarily per spec.
    const progress = Math.min(Math.max(dayNightRatio, 0), 1);

    // SVG Path: M 20 80 (start) A 60 60 0 0 1 140 80 (end arc)
    // Radius is 60. Center is 80, 80.
    // Progress 0 = 180 degrees (left), Progress 1 = 0 degrees (right)
    const angle = 180 - (progress * 180);
    const rad = angle * (Math.PI / 180);
    const r = 60;
    const cx = 80;
    const cy = 80;

    // Calculate sun position on arc
    const sunX = cx + r * Math.cos(rad);
    const sunY = cy - r * Math.sin(rad);

    return (
        <GlassCard style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
            <h3 style={{ alignSelf: 'flex-start', margin: '0 0 1rem 0' }}>Sun Trajectory</h3>

            <div style={{ position: 'relative', width: '160px', height: '100px', display: 'flex', justifyContent: 'center' }}>
                <svg width="160" height="90" viewBox="0 0 160 90">
                    <defs>
                        <linearGradient id="sun-arc-grad" x1="0%" y1="0%" x2="100%" y2="0%">
                            <stop offset="0%" stopColor="rgba(255,154,158,0.8)" />
                            <stop offset="50%" stopColor="#fecbef" />
                            <stop offset="100%" stopColor="rgba(250,112,154,0.8)" />
                        </linearGradient>
                    </defs>

                    {/* Background Arc */}
                    <path
                        d="M 20 80 A 60 60 0 0 1 140 80"
                        fill="none"
                        stroke="rgba(255,255,255,0.1)"
                        strokeWidth="2"
                        strokeDasharray="4 4"
                    />

                    {/* Progress Arc (Drawn up to current time) */}
                    {isDay && (
                        <path
                            d={`M 20 80 A 60 60 0 0 1 ${sunX} ${sunY}`}
                            fill="none"
                            stroke="url(#sun-arc-grad)"
                            strokeWidth="3"
                        />
                    )}

                    {/* Animated Sun / Moon Marker */}
                    <motion.circle
                        r="8"
                        fill={isDay ? "#ffeb3b" : "#e2e8f0"}
                        filter={isDay ? "drop-shadow(0 0 8px #ffeb3b)" : "drop-shadow(0 0 5px #ffffff)"}
                        initial={{ cx: 20, cy: 80 }}
                        animate={{ cx: sunX, cy: sunY }}
                        transition={{ type: "spring", stiffness: 40, damping: 15 }}
                    />
                </svg>

                {/* Labels */}
                <div style={{ position: 'absolute', bottom: '0', left: '10px', fontSize: '0.8rem', color: 'var(--color-text-secondary)' }}>
                    {sunriseStr}
                </div>
                <div style={{ position: 'absolute', bottom: '0', right: '10px', fontSize: '0.8rem', color: 'var(--color-text-secondary)' }}>
                    {sunsetStr}
                </div>
            </div>
        </GlassCard>
    );
}

import React from 'react';
import { motion } from 'framer-motion';

export default function WeatherIcon3D({ conditionId, isDay }) {

    const renderSun = () => (
        <div className="icon-wrapper">
            <motion.div
                className="sun-core"
                style={{
                    width: '80px', height: '80px', borderRadius: '50%',
