    const renderCloud = () => (
        <motion.div
            className="cloud-core"
            style={{
                width: '120px', height: '40px', background: 'linear-gradient(180deg, #ffffff 0%, #e0e0e0 100%)',
                borderRadius: '40px', position: 'absolute', top: '50%', left: '50%',
