                boxShadow: '0 10px 20px rgba(0,0,0,0.1), inset 0 -4px 6px rgba(0,0,0,0.05)'
            }}
            animate={{ y: ['-10%', '-20%', '-10%'] }}
            transition={{ duration: 3, repeat: Infinity, ease: "easeInOut" }}
        >
            <div style={{
                position: 'absolute', width: '50px', height: '50px',
                background: '#ffffff', borderRadius: '50%', top: '-25px', left: '20px'
            }} />
            <div style={{
                position: 'absolute', width: '70px', height: '70px',
                background: '#ffffff', borderRadius: '50%', top: '-40px', right: '15px'
            }} />
        </motion.div>
    );

    const renderRain = () => (
        <div className="icon-wrapper">
            {renderCloud()}
            <div style={{ position: 'absolute', top: '60%', left: '50%', transform: 'translateX(-50%)', display: 'flex', gap: '8px' }}>
                {[0, 0.2, 0.4].map((delay, i) => (
                    <motion.div key={i} style={{
                        width: '4px', height: '15px', background: '#4facfe', borderRadius: '2px'
                    }}
                        animate={{ y: [0, 20], opacity: [1, 0] }}
                        transition={{ duration: 0.8, repeat: Infinity, delay, ease: "linear" }}
                    />
                ))}
            </div>
        </div>
    );

    const renderSnow = () => (
        <div className="icon-wrapper">
            {renderCloud()}
            <div style={{ position: 'absolute', top: '60%', left: '50%', transform: 'translateX(-50%)', display: 'flex', gap: '12px' }}>
                {[0, 1.5, 3].map((delay, i) => (
                    <motion.div key={i} style={{
                        color: 'white', fontSize: '18px', lineHeight: 1, textShadow: '0 0 5px rgba(255,255,255,0.8)'
                    }}
                        animate={{ y: [0, 25], x: [0, i % 2 === 0 ? 5 : -5, 0], opacity: [1, 0], rotate: 360 }}
                        transition={{ duration: 2.5, repeat: Infinity, delay, ease: "linear" }}
                    >
                        ❄
                    </motion.div>
                ))}
            </div>
        </div>
    );

    const renderThunder = () => (
        <div className="icon-wrapper">
            {renderCloud()}
            <motion.svg
                width="40" height="60" viewBox="0 0 24 24"
                style={{ position: 'absolute', top: '50%', left: '50%', x: '-50%', filter: 'drop-shadow(0 0 10px #fdd835)' }}
                animate={{ opacity: [1, 0, 1, 0, 1] }}
                transition={{ duration: 2, repeat: Infinity, repeatDelay: 3, ease: "linear" }}
            >
                <path d="M11 21l-1-7H5l10-12v7h5l-9 12z" fill="#fdd835" />
            </motion.svg>
        </div>
    );

    const renderMoon = () => (
        <div className="icon-wrapper">
            <div style={{
                position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)',
                width: '70px', height: '70px', borderRadius: '50%',
                boxShadow: 'inset -15px -10px 0 0 #fffbea',
                filter: 'drop-shadow(0 0 15px rgba(255, 251, 234, 0.4))'
            }} />
            {[
                { top: '10%', left: '20%', delay: 0 },
                { top: '20%', right: '10%', delay: 0.5 },
                { top: '80%', left: '30%', delay: 1 }
            ].map((star, i) => (
                <motion.div key={i} style={{
                    position: 'absolute', top: star.top, left: star.left, right: star.right,
                    width: '6px', height: '6px', backgroundColor: 'white', borderRadius: '50%',
                    boxShadow: '0 0 8px white'
                }}
                    animate={{ opacity: [0.3, 1, 0.3], scale: [0.8, 1.2, 0.8] }}
                    transition={{ duration: 1.5, repeat: Infinity, delay: star.delay }}
                />
            ))}
        </div>
    );

    const getIconContent = () => {
        if (conditionId >= 200 && conditionId <= 232) return renderThunder();
        if ((conditionId >= 300 && conditionId <= 321) || (conditionId >= 500 && conditionId <= 531)) return renderRain();
        if (conditionId >= 600 && conditionId <= 622) return renderSnow();
        if (conditionId >= 701 && conditionId <= 771) return renderCloud(); // Default to cloud for atmoshpere for now
        if (conditionId === 781) return renderCloud(); // Tornado fallback
        if (conditionId === 800) return isDay ? renderSun() : renderMoon();
        return renderCloud(); // 801-804
    };

    return (
        <div
            className="weather-icon-3d-container"
            style={{
                position: 'relative', width: '160px', height: '160px',
                transformStyle: 'preserve-3d', transform: 'translateZ(40px)'
            }}
        >
            {getIconContent()}
        </div>
    );
}

import React from 'react';
import { motion } from 'framer-motion';
import GlassCard from '../ui/GlassCard';

export default function WindCompass({ speed, deg, unit = 'km/h' }) {
    // Beaufort scale color mapping
    const getWindColor = (spd) => {
        // Assumes km/h for this basic scaling
        if (spd < 20) return '#22c55e'; // Green
        if (spd < 40) return '#facc15'; // Yellow
        if (spd < 60) return '#f97316'; // Orange
        return '#ef4444'; // Red
    };

    const windColor = getWindColor(speed);

    return (
        <GlassCard className="wind-compass-card" style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
            <h3 style={{ alignSelf: 'flex-start', margin: '0 0 1rem 0' }}>Wind</h3>

            <div
                className="compass-container"
                style={{
                    position: 'relative',
                    width: '140px', height: '140px',
                    perspective: '800px'
                }}
            >
                {/* 3D Tilted Compass Face */}
                <motion.div
                    style={{
                        position: 'absolute', inset: 0,
                        borderRadius: '50%',
                        background: 'rgba(0,0,0,0.2)',
                        border: '2px solid rgba(255,255,255,0.1)',
                        rotateX: '45deg', // Creates the 3D oval illusion
                        transformStyle: 'preserve-3d',
                        boxShadow: 'inset 0 10px 20px rgba(0,0,0,0.5), 0 10px 15px rgba(0,0,0,0.3)'
                    }}
                >
                    {/* Tick marks */}
                    {[...Array(12)].map((_, i) => (
                        <div key={i} style={{
                            position: 'absolute', top: 0, left: '50%', width: i % 3 === 0 ? '4px' : '2px',
                            height: i % 3 === 0 ? '10px' : '6px', backgroundColor: 'rgba(255,255,255,0.3)',
                            transformOrigin: '50% 70px',
                            transform: `translateX(-50%) rotate(${i * 30}deg)`
                        }} />
                    ))}

                    {/* Cardinal Points */}
                    <span style={{ position: 'absolute', top: '12px', left: '50%', transform: 'translateX(-50%)', fontSize: '14px', fontWeight: 'bold' }}>N</span>
                    <span style={{ position: 'absolute', bottom: '12px', left: '50%', transform: 'translateX(-50%)', fontSize: '14px', fontWeight: 'bold' }}>S</span>
                    <span style={{ position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)', fontSize: '14px', fontWeight: 'bold' }}>E</span>
                    <span style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', fontSize: '14px', fontWeight: 'bold' }}>W</span>

                    {/* Animated Rotating Needle */}
                    <motion.div
                        className="compass-needle"
                        style={{
                            position: 'absolute', top: '15px', left: '50%',
                            width: '4px', height: '110px',
                            transformOrigin: 'center center'
                        }}
                        initial={{ rotateZ: 0 }}
                        animate={{ rotateZ: deg }} // The OpenWeatherMap wind bearing
                        transition={{ type: 'spring', stiffness: 80, damping: 20 }}
                    >
                        {/* Needle head (North pointing) */}
                        <div style={{
                            width: '0', height: '0',
                            borderLeft: '6px solid transparent',
                            borderRight: '6px solid transparent',
                            borderBottom: `25px solid ${windColor}`,
                            position: 'absolute', left: '-4px', top: 0
                        }} />
                        {/* Needle tail */}
                        <div style={{
                            width: '4px', height: '30px', backgroundColor: 'rgba(255,255,255,0.2)',
                            position: 'absolute', bottom: 0, left: '0'
                        }} />
                    </motion.div>
                </motion.div>

                {/* Central Speed Readout (Flat, not 3D tilted, overlays top) */}
                <div style={{
                    position: 'absolute',
                    top: '50%', left: '50%', transform: 'translate(-50%, -50%) translateZ(40px)',
                    width: '60px', height: '60px',
                    background: 'rgba(20, 20, 30, 0.8)',
                    borderRadius: '50%', backdropFilter: 'blur(4px)',
                    display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center',
                    border: `2px solid ${windColor}`,
                    boxShadow: `0 0 15px ${windColor}66`
                }}>
                    <span style={{ fontSize: '1.2rem', fontWeight: 'bold', lineHeight: 1 }}>{Math.round(speed)}</span>
                    <span style={{ fontSize: '0.6rem', color: 'rgba(255,255,255,0.6)' }}>{unit}</span>
                </div>
            </div>
        </GlassCard>
    );
}

